$$Nao sao literais: 'pull your leg' e brincadeira, nao puxar a perna.$$,
$j$[{"en": "Are you pulling my leg?", "pt": "Voce esta me zoando?"}, {"en": "It cost an arm and a leg.", "pt": "Custou os olhos da cara."}, {"en": "He got cold feet before the wedding.", "pt": "Ele amarelou antes do casamento."}]$j$::jsonb,
