$$Apos 'suggest/insist that', use o verbo sem conjugar: 'that she go', 'that he be'.$$,
$j$[{"en": "I recommend that he see a doctor.", "pt": "Recomendo que ele veja um medico."}, {"en": "They insisted that she be present.", "pt": "Insistiram que ela estivesse presente."}, {"en": "Be that as it may, we proceed.", "pt": "Seja como for, seguimos."}]$j$::jsonb,
