('C2', 4047, $$Enfase: the very / the only$$, $$the very thing / the only one$$, $$ًںژ¯$$,
$$Para enfatizar: 'the very' (exatamente esse - the very thing I needed), 'the only' (o unico), 'the sheer' (puro/absoluto - the sheer size), 'own' (proprio - my own room). Reforcam com elegancia.$$,
$$'The very' = precisamente aquele; 'sheer' = puro/total.$$,
$j$[{"en": "This is the very book I wanted.", "pt": "Este e exatamente o livro que eu queria."}, {"en": "The sheer scale amazed us.", "pt": "A escala absoluta nos impressionou."}, {"en": "I have my own reasons.", "pt": "Tenho minhas proprias razoes."}]$j$::jsonb,
$j$[{"q": "'The very thing' =", "ctx": "", "opts": ["exatamente a coisa", "uma coisa qualquer", "a coisa errada", "quase a coisa"], "ans": 0, "exp": "Precisamente aquela."}, {"q": "'The sheer size' enfatiza:", "ctx": "", "opts": ["o tamanho puro/absoluto", "o tamanho pequeno", "a cor", "o preco"], "ans": 0, "exp": "sheer = puro/total."}, {"q": "'My own car' enfatiza:", "ctx": "", "opts": ["posse/exclusividade", "aluguel", "carro velho", "carro dos outros"], "ans": 0, "exp": "own = proprio."}, {"q": "'The only one' =", "ctx": "", "opts": ["o unico", "um dos varios", "o primeiro", "o ultimo"], "ans": 0, "exp": "Exclusividade."}, {"q": "'The very' vem antes de:", "ctx": "", "opts": ["um substantivo", "um verbo", "um adverbio", "uma preposicao"], "ans": 0, "exp": "the very + substantivo."}, {"q": "Essas formas servem para:", "ctx": "", "opts": ["reforcar com elegancia", "negar", "perguntar", "resumir"], "ans": 0, "exp": "Enfase elegante."}]$j$::jsonb),

('C2', 4048, $$Nominalizacao (academico)$$, $$decide -> the decision to$$, $$ًںژ“$$,
$$Textos academicos preferem substantivos a verbos (nominalizacao). Em vez de 'They decided quickly', escreve-se 'The quick decision...'. 'Prices increased' -> 'The increase in prices'. Deixa o texto mais denso e impessoal.$$,
