$j$[{"en": "The failure of the plan surprised us.", "pt": "O fracasso do plano nos surpreendeu."}, {"en": "There was a sharp rise in costs.", "pt": "Houve um aumento acentuado nos custos."}, {"en": "Her analysis was thorough.", "pt": "A analise dela foi minuciosa."}]$j$::jsonb,
