('C2', 4050, $$Conectores formais raros$$, $$notwithstanding / hence / thereby$$, $$ًں”—$$,
$$Conectores de alto registro: notwithstanding (nao obstante), hence/thus (portanto), thereby (assim/com isso), whereby (pelo qual), henceforth (de agora em diante), albeit (embora). Comuns em textos juridicos/academicos.$$,
$$'Albeit' = although, porem mais formal e curto: 'a small, albeit important, change'.$$,
$j$[{"en": "The plan, albeit risky, worked.", "pt": "O plano, embora arriscado, funcionou."}, {"en": "He was late; hence the delay.", "pt": "Ele atrasou; dai o atraso."}, {"en": "Notwithstanding the cost, we agreed.", "pt": "Nao obstante o custo, concordamos."}]$j$::jsonb,
$j$[{"q": "'Albeit' significa:", "ctx": "", "opts": ["embora (formal)", "portanto", "alem disso", "por exemplo"], "ans": 0, "exp": "= although (formal)."}, {"q": "'Hence' =", "ctx": "", "opts": ["portanto/dai", "porem", "depois", "antes"], "ans": 0, "exp": "Consequencia."}, {"q": "'Notwithstanding' =", "ctx": "", "opts": ["nao obstante/apesar de", "por causa de", "assim que", "enquanto"], "ans": 0, "exp": "Concessao formal."}, {"q": "'Thereby' =", "ctx": "", "opts": ["assim/com isso", "la", "quase", "porem"], "ans": 0, "exp": "Meio/resultado."}, {"q": "Esses conectores aparecem em:", "ctx": "", "opts": ["textos juridicos/academicos", "conversa casual", "memes", "receitas"], "ans": 0, "exp": "Alto registro."}, {"q": "'Henceforth' =", "ctx": "", "opts": ["de agora em diante", "no passado", "porem", "as vezes"], "ans": 0, "exp": "A partir de agora."}]$j$::jsonb),

